/**
 * Marketplace catalog — source of truth for registry.json.
 * Hand-maintained themes are listed here but not regenerated by scaffold.
 */

import { HTML5UP_TEMPLATES, html5UpThemeDef } from "./html5up-defs.ts";

export type CatalogTier = "inspired" | "faithful" | "html5up" | "base";

export interface CatalogEntry {
  slug: string;
  name: string;
  tier: CatalogTier;
  description: string;
  inspiredBy?: string;
  tags: string[];
  version: string;
  /** When true, `deno task scaffold` may regenerate packages/theme-{slug}/ */
  scaffold?: boolean;
}

/** Slugs managed by scripts/scaffold-themes.ts (THEME_DEFS). Empty when all themes are hand-maintained. */
export const SCAFFOLD_SLUGS = new Set<string>([]);

function html5UpCatalogEntries(): CatalogEntry[] {
  return HTML5UP_TEMPLATES.map((t) => {
    const def = html5UpThemeDef(t);
    return {
      slug: t.slug,
      name: t.name,
      tier: "html5up",
      description: def.description,
      inspiredBy: def.upstream,
      tags: def.tags,
      version: "1.0.0",
    };
  });
}

