/** Themes published to the marketplace registry (excludes base theme). */
export const MARKETPLACE_CATALOG = CATALOG.filter((e) => e.tier !== "base");

export function buildRegistryJson(catalog: CatalogEntry[] = MARKETPLACE_CATALOG) {
  return {
    version: 2,
    updatedAt: new Date().toISOString().slice(0, 10),
    themes: catalog.map((e) => ({
      slug: e.slug,
      name: e.name,
      description: e.description,
      author: "Dune Themes",
      version: e.version,
      license: "MIT",
      tags: e.tags,
      tier: e.tier,
      ...(e.inspiredBy ? { inspiredBy: e.inspiredBy } : {}),
      demoUrl: `https://themes.getdune.org/${e.slug}`,
      screenshotUrl: `https://themes.getdune.org/${e.slug}/themes/${e.slug}/static/screenshot.png`,
      jsr: `jsr:@dune/theme-${e.slug}@${e.version}`,
      downloadUrl:
        `https://github.com/duneorg/dune-themes/releases/download/${e.slug}-v${e.version}/${e.slug}-${e.version}.zip`,
      sha256: "",
      verified: true,
      downloads: 0,
      compatibleWith: "^0.28.0",
    })),
  };
}

export function packageDir(slug: string): string {
  return `packages/theme-${slug}`;
}
